'entity.legal.val':   { en: 'SFO RSC Limited',        ar: 'SFO RSC المحدودة' },
'entity.juris.lbl':   { en: 'Jurisdiction',           ar: 'الاختصاص القضائي' },
'entity.juris.val':   { en: 'Abu Dhabi Global Market', ar: 'سوق أبوظبي العالمي' },
'entity.law.lbl':     { en: 'Legal Framework',        ar: 'الإطار القانوني' },
'entity.law.val':     { en: 'English Common Law',     ar: 'القانون العرفي الإنجليزي' },
'entity.reg.lbl':     { en: 'Regulatory Oversight',   ar: 'الرقابة التنظيمية' },
